import type {PropsWithChildren, ReactElement} from 'react';

import {Separator} from '@/components/ui/separator';
import {cn} from '@/lib/utils';

import {Rss} from 'lucide-react';
import {useId} from 'react';

type AppFooterProps = PropsWithChildren<{
  showLinks?: boolean;
  enableCookieButton?: boolean;
  className?: string;
}>;

/**
 * Docker application footer.
 * Always renders the legal bar (copyright, ToS, Privacy, Legal) and social links.
 * When showLinks=true (default), also renders Docker logo + FooterLinkColumn children.
 */
export const AppFooter = ({
  children,
  showLinks = true,
  enableCookieButton = false,
  className,
}: AppFooterProps) => {
  const year = new Intl.DateTimeFormat('en-US', {year: 'numeric'}).format(
    Date.now()
  );

  return (
    <footer
      className={cn(
        'shrink-0 bg-sidebar py-dds-600 text-sidebar-foreground',
        className
      )}
    >
      <div className="mx-auto max-w-screen-2xl px-dds-600">
        {showLinks && (
          <>
            <div className="mb-dds-600 flex flex-wrap items-start gap-dds-800">
              <span className="text-lg font-bold text-foreground">Docker</span>
              {children}
              <FooterCompanyColumn />
            </div>
            <Separator className="mb-dds-600 bg-sidebar-border" />
          </>
        )}
        <div className="flex flex-col items-start justify-between gap-dds-400 md:flex-row md:items-center">
          <div className="flex flex-wrap gap-x-dds-400 gap-y-dds-100 text-sm text-muted-foreground">
            <span className="whitespace-nowrap">
              &copy; {year} Docker, Inc. All rights reserved.
            </span>
            <span aria-hidden="true">|</span>
            <a
              href="https://www.docker.com/legal/docker-terms-service"
              target="_blank"
              rel="noopener noreferrer"
              className="underline underline-offset-4 hover:text-foreground"
            >
              Terms of Service
            </a>
            <span aria-hidden="true">|</span>
            <a
              href="https://www.docker.com/legal/docker-subscription-service-agreement"
              target="_blank"
              rel="noopener noreferrer"
              className="underline underline-offset-4 hover:text-foreground"
            >
              Subscription Service Agreement
            </a>
            <span aria-hidden="true">|</span>
            <a
              href="https://www.docker.com/legal/privacy"
              target="_blank"
              rel="noopener noreferrer"
              className="underline underline-offset-4 hover:text-foreground"
            >
              Privacy
            </a>
            <span aria-hidden="true">|</span>
            <a
              href="https://www.docker.com/legal"
              target="_blank"
              rel="noopener noreferrer"
              className="underline underline-offset-4 hover:text-foreground"
            >
              Legal
            </a>
          </div>
          <SocialLinks />
        </div>
        {enableCookieButton && (
          <button
            type="button"
            id="ot-sdk-btn"
            className="chromatic-ignore ot-sdk-show-settings mt-dds-400 text-sm text-muted-foreground underline underline-offset-4"
          >
            Cookies Settings
          </button>
        )}
      </div>
    </footer>
  );
};

type FooterLinkColumnProps = PropsWithChildren<{
  heading: string;
  className?: string;
}>;

/**
 * A labelled column of links for use inside AppFooter.
 */
export const FooterLinkColumn = ({
  heading,
  children,
  className,
}: FooterLinkColumnProps) => {
  const uid = useId();
  const id = `footer-${uid}-heading`;
  return (
    <section
      aria-labelledby={id}
      className={cn('flex min-w-[8rem] flex-col gap-dds-200', className)}
    >
      <h2 id={id} className="text-sm font-heading text-foreground">
        {heading}
      </h2>
      <div className="flex flex-col gap-dds-100 text-sm text-muted-foreground">
        {children}
      </div>
    </section>
  );
};

const COMPANY_LINKS = [
  {label: 'About Us', href: 'https://www.docker.com/company'},
  {label: 'Blog', href: 'https://www.docker.com/blog/'},
  {label: 'Careers', href: 'https://www.docker.com/careers'},
  {label: 'Contact Us', href: 'https://www.docker.com/company/contact'},
  {label: 'Newsroom', href: 'https://www.docker.com/company/newsroom'},
  {label: 'System Status', href: 'https://www.dockerstatus.com'},
] as const;

const FooterCompanyColumn = () => (
  <FooterLinkColumn heading="Company">
    {COMPANY_LINKS.map(({label, href}) => (
      <a
        key={href}
        href={href}
        target="_blank"
        rel="noopener noreferrer"
        className="hover:text-foreground"
      >
        {label}
      </a>
    ))}
  </FooterLinkColumn>
);

