const SOCIAL_LINKS: Array<{
  label: string;
  href: string;
  Icon: () => ReactElement;
}> = [
  {
    label: 'Visit our LinkedIn page',
    href: 'https://www.linkedin.com/company/docker',
    Icon: LinkedInIcon,
  },
  {label: 'Visit our X page', href: 'https://x.com/docker', Icon: XIcon},
  {
    label: 'Visit our YouTube page',
    href: 'https://www.youtube.com/user/dockerrun',
    Icon: YouTubeIcon,
  },
  {
    label: 'Visit our RSS feed',
    href: 'https://www.docker.com/feed/',
    Icon: () => <Rss aria-hidden="true" className="size-4" />,
  },
];

const SocialLinks = () => (
  <div className="flex gap-dds-100">
    {SOCIAL_LINKS.map(({label, href, Icon}) => (
      <a
        key={href}
        href={href}
        target="_blank"
        rel="noopener noreferrer"
        aria-label={label}
        className="rounded p-dds-200 text-muted-foreground transition-colors hover:text-foreground"
      >
        <Icon />
      </a>
    ))}
  </div>
);
